/**
 * Logs Store
 * 
 * WordPress Data Store for managing plugin logs and monitoring
 */

import { registerStore } from '@wordpress/data';
import * as actions from './actions';
import * as selectors from './selectors';
import * as resolvers from './resolvers';

const DEFAULT_STATE = {
    logs: [],
    pagination: {
        page: 1,
        perPage: 50,
        totalPages: 0,
        totalItems: 0,
    },
    stats: {
        total: 0,
        by_level: {},
        by_component: {},
    },
    settings: {
        logging_enabled: true,
        log_level: 'info',
        retention_days: 30,
        levels: [],
        components: [],
    },
    isLoading: false,
    error: null,
    autoRefresh: false,
};

const reducer = (state = DEFAULT_STATE, action) => {
    switch (action.type) {
        case 'SET_LOGS':
            return {
                ...state,
                logs: action.logs,
                isLoading: false,
            };
        
        case 'SET_PAGINATION':
            return {
                ...state,
                pagination: action.pagination,
            };
        
        case 'SET_STATS':
            return {
                ...state,
                stats: action.stats,
            };
        
        case 'SET_SETTINGS':
            return {
                ...state,
                settings: action.settings,
            };
        
        case 'SET_LOADING':
            return {
                ...state,
                isLoading: action.isLoading,
            };
        
        case 'SET_ERROR':
            return {
                ...state,
                error: action.error,
                isLoading: false,
            };
        
        case 'SET_AUTO_REFRESH':
            return {
                ...state,
                autoRefresh: action.autoRefresh,
            };
        
        case 'SET_FILTERS':
            return {
                ...state,
                filters: action.filters,
            };
        
        default:
            return state;
    }
};

// Controls for handling generator actions
const controls = {
    API_FETCH({ request }) {
        return window.wp.apiFetch(request);
    },
    SELECT({ storeName, selectorName, args = [] }) {
        return window.wp.data.select(storeName)[selectorName](...args);
    },
};

// Register the store
registerStore('gg-data/logs', {
    reducer,
    actions,
    selectors,
    resolvers,
    controls,
});

export default 'gg-data/logs';
