/**
 * Logs Store - Selectors
 * 
 * Selector functions for accessing logs state
 */

import { createSelector } from '@wordpress/data';

// Basic selectors
export const getLogs = (state) => state.logs || [];

export const getPagination = (state) => state.pagination || {
    page: 1,
    perPage: 50,
    totalPages: 0,
    totalItems: 0,
};

export const getStats = (state) => state.stats || {
    total: 0,
    by_level: {},
    by_component: {},
};

export const getSettings = (state) => state.settings || {
    logging_enabled: true,
    log_level: 'info',
    retention_days: 30,
    levels: [],
    components: [],
};

export const isLoading = (state) => state.isLoading || false;

export const getError = (state) => state.error || null;

export const getAutoRefresh = (state) => state.autoRefresh || false;

// Memoized selectors
export const getLogCount = createSelector(
    (state) => (state.stats && state.stats.total) || 0,
    (state) => [state.stats]
);

export const getLevelCounts = createSelector(
    (state) => (state.stats && state.stats.by_level) || {},
    (state) => [state.stats]
);

export const getComponentCounts = createSelector(
    (state) => (state.stats && state.stats.by_component) || {},
    (state) => [state.stats]
);

export const getLevelOptions = createSelector(
    (state) => {
        const levels = (state.settings && state.settings.levels) || [];
        const counts = (state.stats && state.stats.by_level) || {};
        
        return levels.map(level => ({
            label: `${level.charAt(0).toUpperCase() + level.slice(1)} (${counts[level] || 0})`,
            value: level,
        }));
    },
    (state) => [state.settings, state.stats]
);

export const getComponentOptions = createSelector(
    (state) => {
        const components = (state.settings && state.settings.components) || [];
        const counts = (state.stats && state.stats.by_component) || {};
        
        return components.map(component => ({
            label: `${component.charAt(0).toUpperCase() + component.slice(1)} (${counts[component] || 0})`,
            value: component,
        }));
    },
    (state) => [state.settings, state.stats]
);

export const getLogById = createSelector(
    (state, logId) => {
        if (!state.logs) return null;
        return state.logs.find(log => log.id === logId) || null;
    },
    (state, logId) => [state.logs, logId]
);

export const getLogsWithContext = createSelector(
    (state) => {
        if (!state.logs) return [];
        
        return state.logs.map(log => ({
            ...log,
            contextData: log.context ? (typeof log.context === 'string' ? JSON.parse(log.context) : log.context) : {},
        }));
    },
    (state) => [state.logs]
);
